from dataclasses import dataclass, asdict
import torch
import torch.nn as nn
from transformers import AutoModel


@dataclass
class FTConfig:
    encoder_name: str = 'facebook/wav2vec2-xls-r-300m'
    proj_dim: int = 256
    dropout: float = 0.2
    unfreeze_last_n_layers: int = 4
    freeze_feature_encoder: bool = True
    def to_dict(self):
        return asdict(self)


class MeanStdPool(nn.Module):
    def forward(self, x, mask=None):
        if mask is None:
            m = x.mean(1)
            v = x.var(1, unbiased=False)
            return torch.cat([m, torch.sqrt(v.clamp_min(1e-5))], -1)
        mask = mask.unsqueeze(-1).float()
        den = mask.sum(1).clamp_min(1.0)
        m = (x * mask).sum(1) / den
        v = (((x - m.unsqueeze(1)) ** 2) * mask).sum(1) / den
        return torch.cat([m, torch.sqrt(v.clamp_min(1e-5))], -1)


class AttentiveStatsPool(nn.Module):
    def __init__(self, dim, hidden=128):
        super().__init__()
        self.attn = nn.Sequential(nn.Linear(dim, hidden), nn.Tanh(), nn.Linear(hidden, 1))
    def forward(self, x, mask=None):
        a = self.attn(x).squeeze(-1)
        if mask is not None:
            a = a.masked_fill(mask == 0, -1e4)
        w = torch.softmax(a, 1)
        m = torch.sum(x * w.unsqueeze(-1), 1)
        v = torch.sum(((x - m.unsqueeze(1)) ** 2) * w.unsqueeze(-1), 1)
        return torch.cat([m, torch.sqrt(v.clamp_min(1e-5))], -1)


class _BaseDetector(nn.Module):
    def _layers(self):
        if hasattr(self.encoder, 'encoder') and hasattr(self.encoder.encoder, 'layers'):
            return self.encoder.encoder.layers
        if hasattr(self.encoder, 'wav2vec2') and hasattr(self.encoder.wav2vec2.encoder, 'layers'):
            return self.encoder.wav2vec2.encoder.layers
        return None
    def _freeze_all(self):
        for p in self.encoder.parameters():
            p.requires_grad = False
    def _unfreeze_last(self, n_last):
        layers = self._layers()
        if layers is not None and n_last > 0:
            for layer in layers[-n_last:]:
                for p in layer.parameters():
                    p.requires_grad = True
    def _downsample_mask(self, mask, feat_len):
        if mask is None:
            return None
        if mask.size(1) == feat_len:
            return mask
        idx = torch.linspace(0, mask.size(1) - 1, feat_len, device=mask.device).long()
        return mask[:, idx]


class BaselineDetector(_BaseDetector):
    def __init__(self, encoder_name='facebook/wav2vec2-base', pooling='attentive', head_hidden_dim=256, dropout=0.2, unfreeze_last_n=0):
        super().__init__()
        self.encoder = AutoModel.from_pretrained(encoder_name, local_files_only=True)
        hs = self.encoder.config.hidden_size
        self.pool = AttentiveStatsPool(hs) if pooling == 'attentive' else MeanStdPool()
        self.bn = nn.BatchNorm1d(head_hidden_dim)
        self.head = nn.Sequential(
            nn.Linear(hs * 2, head_hidden_dim),
            nn.ReLU(),
            nn.Dropout(dropout),
            nn.Linear(head_hidden_dim, 1),
        )
        self._freeze_all()
        self._unfreeze_last(unfreeze_last_n)
    def forward(self, input_values, attention_mask=None):
        out = self.encoder(input_values=input_values, attention_mask=attention_mask, return_dict=True)
        x = out.last_hidden_state
        m = self._downsample_mask(attention_mask, x.size(1))
        z = self.pool(x, m)
        z = self.head[0](z)
        z = self.bn(z)
        z = self.head[1](z)
        z = self.head[2](z)
        z = self.head[3](z).squeeze(-1)
        return {'logits': z}


class SpoofDetector(_BaseDetector):
    def __init__(self, cfg: FTConfig):
        super().__init__()
        self.cfg = cfg
        self.encoder = AutoModel.from_pretrained(cfg.encoder_name, local_files_only=True)
        hs = self.encoder.config.hidden_size
        self.pool = MeanStdPool()
        self.proj = nn.Sequential(
            nn.Linear(hs * 2, cfg.proj_dim),
            nn.BatchNorm1d(cfg.proj_dim),
            nn.GELU(),
            nn.Dropout(cfg.dropout),
        )
        self.cls = nn.Linear(cfg.proj_dim, 1)
        self._freeze_all()
        self._unfreeze_last(cfg.unfreeze_last_n_layers)
    def forward(self, input_values, attention_mask=None):
        out = self.encoder(input_values=input_values, attention_mask=attention_mask, return_dict=True)
        x = out.last_hidden_state
        m = self._downsample_mask(attention_mask, x.size(1))
        z = self.pool(x, m)
        z = self.proj(z)
        z = self.cls(z).squeeze(-1)
        return {'logits': z}


def build_model(model_name='baseline', **kwargs):
    if model_name == 'baseline':
        return BaselineDetector(**kwargs)
    if model_name == 'ft':
        return SpoofDetector(FTConfig(**kwargs))
    raise ValueError(model_name)


def _get_state_dict(ckpt):
    if isinstance(ckpt, dict):
        for k in ['model_state', 'model_state_dict', 'state_dict']:
            if k in ckpt and isinstance(ckpt[k], dict):
                return ckpt[k]
        t = {k: v for k, v in ckpt.items() if torch.is_tensor(v)}
        if t:
            return t
    return ckpt


def build_model_from_checkpoint(ckpt):
    sd = _get_state_dict(ckpt)
    top = ckpt if isinstance(ckpt, dict) else {}
    if 'proj.0.weight' in sd or 'cls.weight' in sd:
        mk = dict(top.get('model_kwargs', {})) if isinstance(top.get('model_kwargs'), dict) else {}
        enc = top.get('encoder_name') or mk.get('encoder_name') or 'facebook/wav2vec2-xls-r-300m'
        proj_dim = int(sd['proj.0.weight'].shape[0]) if 'proj.0.weight' in sd else int(mk.get('proj_dim', 256))
        model = SpoofDetector(FTConfig(encoder_name=enc, proj_dim=proj_dim, dropout=float(mk.get('dropout', 0.2)), unfreeze_last_n_layers=int(mk.get('unfreeze_last_n_layers', mk.get('unfreeze_last_n', 0)))))
        model.load_state_dict(sd, strict=False)
        return model
    enc = top.get('encoder_name') or 'facebook/wav2vec2-base'
    if isinstance(top.get('model_config'), dict):
        enc = top['model_config'].get('encoder_name', enc)
    if isinstance(top.get('model_kwargs'), dict):
        enc = top['model_kwargs'].get('encoder_name', enc)
    hidden = int(sd['head.0.weight'].shape[0]) if 'head.0.weight' in sd else 256
    pooling = 'attentive' if any(k.startswith('pool.attn.') for k in sd.keys()) else 'meanstd'
    model = BaselineDetector(encoder_name=enc, pooling=pooling, head_hidden_dim=hidden, dropout=0.2, unfreeze_last_n=0)
    model.load_state_dict(sd, strict=False)
    return model
